use axum::{routing::post, Router, Json};
use serde_json::Value;
use std::sync::Arc;
use tokio::net::TcpListener;
use axum::extract::State;

mod postgres_repo;
mod algorithms;

use postgres_repo::{PostgresRepository, SongResponse};
use algorithms::{binary_search, radix_sort, A2Tree};

#[derive(Clone)]
struct AppState {
 repo: Arc<PostgresRepository>,
}

#[tokio::main]
async fn main() {
 let repo = Arc::new(PostgresRepository::new().await);
 let state = AppState { repo };

 let app = Router::new()
 .route("/api/v1/query", post(query))
 .with_state(state);

 println!("Server started at http://127.0.0.1:8080");

 let listener = TcpListener::bind("0.0.0.0:8080").await.unwrap();
 axum::serve(listener, app).await.unwrap();
}

async fn query(
 State(state): State<AppState>,
 Json(body): Json<Value>,
) -> Json<Value> {

 let method = body["method"].as_str().unwrap_or("");
 let entity = body["entity"].as_str().unwrap_or("");

 if method == "read" && entity == "song" {

 let mut songs = state.repo.get_songs(body["filters"].clone()).await;

 // =========================
 // 🔥 RADIX SORT (оставили как было)
 // =========================
 radix_sort(&mut songs);

 // =========================
 // 🔥 BINARY SEARCH (ID)
 // =========================
 if let Some(min) = body["filters"]["song_id"]["min"].as_i64() {
 if let Some(max) = body["filters"]["song_id"]["max"].as_i64() {

 songs.sort_by_key(|s| s.song_id);

 let left = binary_search(&songs, min as i32);
 let right = binary_search(&songs, max as i32);

 if let (Some(l), Some(r)) = (left, right) {
 songs = songs[l..=r].to_vec();
 } else {
 songs.clear();
 }
 }
 }

 // =========================
 // 🔥 A2 TREE
 // =========================
 if let Some(name) = body["filters"]["song_name"].as_str() {
 let mut tree = A2Tree::new();
 for s in songs.clone() {
 tree.insert(s.song_name.clone(), s);
 }
 songs = tree.search(name.to_string());
 }

 if let Some(album) = body["filters"]["album_name"].as_str() {
 let mut tree = A2Tree::new();
 for s in songs.clone() {
 tree.insert(s.album_name.clone(), s);
 }
 songs = tree.search(album.to_string());
 }

 if let Some(author) = body["filters"]["author"].as_str() {
 let mut tree = A2Tree::new();
 for s in songs.clone() {
 tree.insert(s.author.clone(), s);
 }
 songs = tree.search(author.to_string());
 }

 // =========================
 // 🔥 duration (точное совпадение)
 // =========================
 if let Some(dur) = body["filters"]["duration_max"].as_i64() {
 songs = songs.into_iter()
 .filter(|s| s.duration_sec == dur as i32)
 .collect();
 }

 // =========================
 // 🔥 ДОБАВЛЕННАЯ СОРТИРОВКА (UI)
 // =========================
 let sort_field = body["sort"]["field"].as_str().unwrap_or("");
 let sort_order = body["sort"]["order"].as_str().unwrap_or("asc");

 match sort_field {

 "song_id" => {
 radix_sort(&mut songs);
 }

 "year" => {
 songs.sort_by_key(|s| s.year);
 }

 "duration_sec" => {
 songs.sort_by_key(|s| s.duration_sec);
 }

 "song_name" => {
 songs.sort_by(|a, b| a.song_name.to_lowercase().cmp(&b.song_name.to_lowercase()));
 }

 "author" => {
 songs.sort_by(|a, b| a.author.to_lowercase().cmp(&b.author.to_lowercase()));
 }

 _ => {}
 }

 if sort_order == "desc" {
 songs.reverse();
 }

 return Json(serde_json::json!({
 "error": 0,
 "data": { "items": songs }
 }));
 }

 Json(serde_json::json!({
 "error": 1,
 "error_message": "Unknown request"
 }))
}

use axum::http::StatusCode;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ErrorCode {
 None = 0,
 DbConnection = 1,
 NotFound = 2,
 QueryBuild = 3,
 InvalidClientRequest = 4,
 ResponseBuild = 5,
 DbRead = 6,
 Unknown = 7,
}

impl ErrorCode {
 pub fn as_u8(self) -> u8 {
 self as u8
 }
}

#[derive(Debug, Clone)]
pub struct ApiError {
 pub code: ErrorCode,
 pub message: String,
}

impl ApiError {
 pub fn new(code: ErrorCode, message: impl Into<String>) -> Self {
 Self {
 code,
 message: message.into(),
 }
 }

 pub fn invalid_request(message: impl Into<String>) -> Self {
 Self::new(ErrorCode::InvalidClientRequest, message)
 }

 pub fn not_found(message: impl Into<String>) -> Self {
 Self::new(ErrorCode::NotFound, message)
 }

 pub fn from_repo_error(err: RepoError) -> Self {
 match err {
 RepoError::Connection(m) => Self::new(ErrorCode::DbConnection, m),
 RepoError::Read(m) => Self::new(ErrorCode::DbRead, m),
 RepoError::Query(m) => Self::new(ErrorCode::QueryBuild, m),
 RepoError::Unknown(m) => Self::new(ErrorCode::Unknown, m),
 }
 }

 pub fn http_status(&self) -> StatusCode {
 match self.code {
 ErrorCode::None => StatusCode::OK,
 ErrorCode::InvalidClientRequest => StatusCode::BAD_REQUEST,
 ErrorCode::NotFound => StatusCode::NOT_FOUND,
 ErrorCode::DbConnection | ErrorCode::DbRead => StatusCode::SERVICE_UNAVAILABLE,
 ErrorCode::QueryBuild => StatusCode::INTERNAL_SERVER_ERROR,
 ErrorCode::ResponseBuild | ErrorCode::Unknown => StatusCode::INTERNAL_SERVER_ERROR,
 }
 }
}

#[derive(Debug, Clone)]
#[allow(dead_code)]
pub enum RepoError {
 Connection(String),
 Read(String),
 Query(String),
 Unknown(String),
}

use std::cmp::Ordering;

type Link<T> = Option<Box<Node<T>>>;

#[derive(Debug)]
struct Node<T> {
 value: T,
 left: Link<T>,
 right: Link<T>,
}

impl<T> Node<T> {
 fn new(value: T) -> Self {
 Self {
 value,
 left: None,
 right: None,
 }
 }
}

#[derive(Debug, Default)]
pub struct A2Tree<T> {
 root: Link<T>,
 len: usize,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct WeightedKey<T> {
 pub key: T,
 pub weight: u64,
}

impl<T> A2Tree<T> {
 pub fn new() -> Self {
 Self { root: None, len: 0 }
 }

 pub fn len(&self) -> usize {
 self.len
 }

 pub fn is_empty(&self) -> bool {
 self.len == 0
 }

 pub fn insert_by<F>(&mut self, value: T, cmp: F) -> bool
 where
 F: Copy + Fn(&T, &T) -> Ordering,
 {
 let inserted = Self::insert_node(&mut self.root, value, cmp);
 if inserted {
 self.len += 1;
 }
 inserted
 }

 pub fn contains_by<F>(&self, target: &T, cmp: F) -> bool
 where
 F: Copy + Fn(&T, &T) -> Ordering,
 {
 let mut current = self.root.as_deref();
 while let Some(node) = current {
 match cmp(target, &node.value) {
 Ordering::Less => current = node.left.as_deref(),
 Ordering::Greater => current = node.right.as_deref(),
 Ordering::Equal => return true,
 }
 }
 false
 }

 pub fn inorder<'a>(&'a self, out: &mut Vec<&'a T>) {
 fn walk<'a, T>(link: &'a Link<T>, out: &mut Vec<&'a T>) {
 if let Some(node) = link {
 walk(&node.left, out);
 out.push(&node.value);
 walk(&node.right, out);
 }
 }
 walk(&self.root, out);
 }

 // A2: builds a near-optimal search tree from sorted keys using key weights.
 pub fn build_from_sorted_by_weight<F>(items: &[T], weight: F) -> Self
 where
 T: Clone,
 F: Copy + Fn(&T) -> u64,
 {
 fn build<T, F>(items: &[T], weight: F) -> Link<T>
 where
 T: Clone,
 F: Copy + Fn(&T) -> u64,
 {
 if items.is_empty() {
 return None;
 }

 let idx = a2_root_index(items, weight);
 Some(Box::new(Node {
 value: items[idx].clone(),
 left: build(&items[..idx], weight),
 right: build(&items[idx + 1..], weight),
 }))
 }

 let root = build(items, weight);
 Self {
 root,
 len: items.len(),
 }
 }

 fn insert_node<F>(node: &mut Link<T>, value: T, cmp: F) -> bool
 where
 F: Copy + Fn(&T, &T) -> Ordering,
 {
 match node {
 None => {
 *node = Some(Box::new(Node::new(value)));
 true
 }
 Some(current) => match cmp(&value, &current.value) {
 Ordering::Less => Self::insert_node(&mut current.left, value, cmp),
 Ordering::Greater => Self::insert_node(&mut current.right, value, cmp),
 Ordering::Equal => false,
 },
 }
 }
}

fn a2_root_index<T, F>(items: &[T], weight: F) -> usize
where
 F: Copy + Fn(&T) -> u64,
{
 let total_weight: u64 = items.iter().map(weight).sum();
 if total_weight == 0 {
 return items.len() / 2;
 }

 let half = total_weight / 2;
 let mut prefix = 0_u64;

 for (i, item) in items.iter().enumerate() {
 let w = weight(item);
 if prefix < half && prefix + w >= half {
 return i;
 }
 prefix += w;
 }

 items.len() - 1
}

use std::collections::VecDeque;
use std::sync::Mutex;

use chrono::Utc;

use crate::models::{Entity, RequestLogEntry};

pub struct RequestLogger {
 cap: usize,
 inner: Mutex<VecDeque<RequestLogEntry>>,
}

impl RequestLogger {
 pub fn new(cap: usize) -> Self {
 Self {
 cap,
 inner: Mutex::new(VecDeque::with_capacity(cap)),
 }
 }

 pub fn push(&self, ip: String, entity: Entity, error: u8, error_message: Option<String>) {
 let mut guard = match self.inner.lock() {
 Ok(g) => g,
 Err(_) => return,
 };

 if guard.len() >= self.cap {
 guard.pop_front();
 }

 guard.push_back(RequestLogEntry {
 timestamp_utc: Utc::now().to_rfc3339(),
 ip,
 entity,
 error,
 error_message,
 });
 }

 pub fn list(&self) -> Vec<RequestLogEntry> {
 match self.inner.lock() {
 Ok(g) => g.iter().cloned().collect(),
 Err(_) => Vec::new(),
 }
 }
}

use std::cmp::Ordering;
use std::ops::Range;

pub fn binary_search_by<T, F>(slice: &[T], target: &T, cmp: F) -> Option<usize>
where
 F: Fn(&T, &T) -> Ordering,
{
 let idx = lower_bound_by(slice, target, &cmp);
 if idx < slice.len() && cmp(&slice[idx], target) == Ordering::Equal {
 Some(idx)
 } else {
 None
 }
}

pub fn lower_bound_by<T, F>(slice: &[T], target: &T, cmp: F) -> usize
where
 F: Fn(&T, &T) -> Ordering,
{
 let mut left = 0_usize;
 let mut right = slice.len();
 while left < right {
 let mid = left + (right - left) / 2;
 if cmp(&slice[mid], target) == Ordering::Less {
 left = mid + 1;
 } else {
 right = mid;
 }
 }
 left
}

pub fn upper_bound_by<T, F>(slice: &[T], target: &T, cmp: F) -> usize
where
 F: Fn(&T, &T) -> Ordering,
{
 let mut left = 0_usize;
 let mut right = slice.len();
 while left < right {
 let mid = left + (right - left) / 2;
 if cmp(&slice[mid], target) == Ordering::Greater {
 right = mid;
 } else {
 left = mid + 1;
 }
 }
 left
}

pub fn equal_range_by<T, F>(slice: &[T], target: &T, cmp: F) -> Range<usize>
where
 F: Copy + Fn(&T, &T) -> Ordering,
{
 let left = lower_bound_by(slice, target, cmp);
 let right = upper_bound_by(slice, target, cmp);
 left..right
}

use std::cmp::Ordering;
use std::sync::Arc;

use crate::error::{ApiError, ErrorCode};
use crate::models::{
 AlbumRecord, ApiRequest, ApiResponse, AuthorPayload, Entity, Filters, RangeFilter,
 ResponseData, SongRecord, Sort, SortField, SortOrder,
};
use crate::repo::MediaRepository;

#[derive(Clone)]
pub struct SearchService {
 repo: Arc<dyn MediaRepository>,
}

impl SearchService {
 pub fn new(repo: Arc<dyn MediaRepository>) -> Self {
 Self { repo }
 }

 pub fn execute(&self, request: ApiRequest) -> Result<ApiResponse, ApiError> {
 validate_request(&request)?;

 match request.entity {
 Entity::Song => self.search_songs(request),
 Entity::Album => self.search_albums(request),
 Entity::Author => self.search_author(request),
 }
 }

 fn search_songs(&self, request: ApiRequest) -> Result<ApiResponse, ApiError> {
 let mut songs = self
 .repo
 .all_songs()
 .map_err(ApiError::from_repo_error)?
 .into_iter()
 .filter(|song| apply_song_filters(song, &request.filters))
 .collect::<Vec<_>>();

 apply_song_sort(&mut songs, &request.sort)?;

 if songs.is_empty() {
 return Err(ApiError::not_found(
 "Songs were not found by provided filters",
 ));
 }

 Ok(ok_response(request, ResponseData::Song(songs)))
 }

 fn search_albums(&self, request: ApiRequest) -> Result<ApiResponse, ApiError> {
 let mut albums = self
 .repo
 .all_albums()
 .map_err(ApiError::from_repo_error)?
 .into_iter()
 .filter(|album| apply_album_filters(album, &request.filters))
 .collect::<Vec<_>>();

 apply_album_sort(&mut albums, &request.sort)?;

 if albums.is_empty() {
 return Err(ApiError::not_found(
 "Albums were not found by provided filters",
 ));
 }

 Ok(ok_response(request, ResponseData::Album(albums)))
 }

 fn search_author(&self, request: ApiRequest) -> Result<ApiResponse, ApiError> {
 let author = request.filters.author.clone().ok_or_else(|| {
 ApiError::invalid_request("For entity=author, filters.author is required")
 })?;

 let albums = self
 .repo
 .all_albums()
 .map_err(ApiError::from_repo_error)?
 .into_iter()
 .filter(|a| a.author.eq_ignore_ascii_case(&author))
 .collect::<Vec<_>>();

 let mut images = self
 .repo
 .author_images(&author)
 .map_err(ApiError::from_repo_error)?;
 images.truncate(6);

 if albums.is_empty() && images.is_empty() {
 return Err(ApiError::not_found("Author media was not found"));
 }

 let payload = AuthorPayload {
 author,
 albums,
 images,
 };

 Ok(ok_response(request, ResponseData::Author(payload)))
 }
}

fn ok_response(request: ApiRequest, data: ResponseData) -> ApiResponse {
 ApiResponse {
 entity: Some(request.entity),
 filters: request.filters,
 sort: request.sort,
 error: ErrorCode::None.as_u8(),
 error_message: None,
 data: Some(data),
 }
}

pub fn error_response(request: ApiRequest, err: ApiError) -> ApiResponse {
 ApiResponse {
 entity: Some(request.entity),
 filters: request.filters,
 sort: request.sort,
 error: err.code.as_u8(),
 error_message: Some(err.message),
 data: None,
 }
}

fn validate_range(name: &str, range: &RangeFilter) -> Result<(), ApiError> {
 if range.min > range.max {
 return Err(ApiError::invalid_request(format!(
 "Invalid range in filters.{name}: min must be <= max"
 )));
 }
 Ok(())
}

fn validate_request(request: &ApiRequest) -> Result<(), ApiError> {
 if let Some(range) = &request.filters.song_id {
 validate_range("song_id", range)?;
 }
 if let Some(range) = &request.filters.album_id {
 validate_range("album_id", range)?;
 }
 if let Some(range) = &request.filters.year {
 validate_range("year", range)?;
 }

 let sort_is_partial = request.sort.field.is_some() ^ request.sort.order.is_some();
 if sort_is_partial {
 return Err(ApiError::invalid_request(
 "sort.field and sort.order must be both null or both specified",
 ));
 }

 match request.entity {
 Entity::Song => validate_song_sort(&request.sort),
 Entity::Album => validate_album_sort(&request.sort),
 Entity::Author => {
 if request.sort.field.is_some() || request.sort.order.is_some() {
 return Err(ApiError::invalid_request(
 "entity=author does not support sorting",
 ));
 }
 Ok(())
 }
 }
}

fn validate_song_sort(sort: &Sort) -> Result<(), ApiError> {
 match sort.field {
 Some(SortField::Year | SortField::SongName | SortField::AlbumName | SortField::Author)
 | None => Ok(()),
 }
}

fn validate_album_sort(sort: &Sort) -> Result<(), ApiError> {
 match sort.field {
 Some(SortField::Year | SortField::AlbumName | SortField::Author) | None => Ok(()),
 Some(SortField::SongName) => Err(ApiError::invalid_request(
 "song_name sorting is not supported for entity=album",
 )),
 }
}

fn apply_song_filters(song: &SongRecord, f: &Filters) -> bool {
 if let Some(range) = &f.song_id {
 if song.song_id < range.min || song.song_id > range.max {
 return false;
 }
 }
 if let Some(author) = &f.author {
 if !song.author.eq_ignore_ascii_case(author) {
 return false;
 }
 }
 if let Some(album_name) = &f.album_name {
 if !song.album_name.eq_ignore_ascii_case(album_name) {
 return false;
 }
 }
 if let Some(song_name) = &f.song_name {
 if !song.song_name.eq_ignore_ascii_case(song_name) {
 return false;
 }
 }
 if let Some(range) = &f.year {
 if song.year < range.min || song.year > range.max {
 return false;
 }
 }
 if let Some(max_duration) = f.duration_max {
 if song.duration_sec > max_duration {
 return false;
 }
 }
 true
}

fn apply_album_filters(album: &AlbumRecord, f: &Filters) -> bool {
 if let Some(range) = &f.album_id {
 if album.album_id < range.min || album.album_id > range.max {
 return false;
 }
 }
 if let Some(author) = &f.author {
 if !album.author.eq_ignore_ascii_case(author) {
 return false;
 }
 }
 if let Some(album_name) = &f.album_name {
 if !album.album_name.eq_ignore_ascii_case(album_name) {
 return false;
 }
 }
 if let Some(range) = &f.year {
 if album.year < range.min || album.year > range.max {
 return false;
 }
 }
 true
}

fn apply_song_sort(songs: &mut [SongRecord], sort: &Sort) -> Result<(), ApiError> {
 let Some(field) = &sort.field else {
 return Ok(());
 };
 let Some(order) = &sort.order else {
 return Ok(());
 };

 songs.sort_by(|a, b| {
 let cmp = match field {
 SortField::Year => a.year.cmp(&b.year),
 SortField::SongName => a.song_name.to_lowercase().cmp(&b.song_name.to_lowercase()),
 SortField::AlbumName => a
 .album_name
 .to_lowercase()
 .cmp(&b.album_name.to_lowercase()),
 SortField::Author => a.author.to_lowercase().cmp(&b.author.to_lowercase()),
 };

 match order {
 SortOrder::Asc => cmp,
 SortOrder::Desc => reverse(cmp),
 }
 });

 Ok(())
}

fn apply_album_sort(albums: &mut [AlbumRecord], sort: &Sort) -> Result<(), ApiError> {
 let Some(field) = &sort.field else {
 return Ok(());
 };
 let Some(order) = &sort.order else {
 return Ok(());
 };

 albums.sort_by(|a, b| {
 let cmp = match field {
 SortField::Year => a.year.cmp(&b.year),
 SortField::AlbumName => a
 .album_name
 .to_lowercase()
 .cmp(&b.album_name.to_lowercase()),
 SortField::Author => a.author.to_lowercase().cmp(&b.author.to_lowercase()),
 SortField::SongName => Ordering::Equal,
 };

 match order {
 SortOrder::Asc => cmp,
 SortOrder::Desc => reverse(cmp),
 }
 });

 Ok(())
}

fn reverse(cmp: Ordering) -> Ordering {
 match cmp {
 Ordering::Less => Ordering::Greater,
 Ordering::Equal => Ordering::Equal,
 Ordering::Greater => Ordering::Less,
 }
}

#[cfg(test)]
mod tests {
 use std::sync::Arc;

 use crate::models::{ApiRequest, Entity, Filters, RangeFilter, Sort, SortField, SortOrder};
 use crate::repo::InMemoryRepository;

 use super::SearchService;

 #[test]
 fn song_filter_and_sort_desc_year_works() {
 let service = SearchService::new(Arc::new(InMemoryRepository::new_seeded()));
 let req = ApiRequest {
 entity: Entity::Song,
 filters: Filters {
 song_id: Some(RangeFilter { min: 10, max: 72 }),
 author: Some("Linkin Park".to_string()),
 year: Some(RangeFilter {
 min: 2000,
 max: 2010,
 }),
 duration_max: Some(300),
 ..Filters::default()
 },
 sort: Sort {
 field: Some(SortField::Year),
 order: Some(SortOrder::Desc),
 },
 };

 let out = service.execute(req).expect("must work");
 let data = out.data.expect("must have data");

 match data {
 crate::models::ResponseData::Song(songs) => {
 assert_eq!(songs.len(), 2);
 assert_eq!(songs[0].year, 2007);
 assert_eq!(songs[1].year, 2003);
 }
